# monitoring/sli_definitions.py
# SLI computation functions for a GenAI API integration service.
from dataclasses import dataclass
from typing import Optional
import requests

PROMETHEUS = 'http://prometheus:9090'

@dataclass
class SLIValue:
    name: str
    value: float
    unit: str
    window: str

def prom(query: str, timeout: int = 5) -> Optional[float]:
    r = requests.get(f'{PROMETHEUS}/api/v1/query',
                     params={'query': query}, timeout=timeout)
    result = r.json()['data']['result']
    return float(result[0]['value'][1]) if result else None

def availability_sli(window: str = '30d') -> SLIValue:
    # Exclude 4xx errors (client-side, not service failures)
    good = prom(
        f'sum(rate(http_requests_total{{status!~"4..",status!~"5.."}}[{window}]))'
    )
    total = prom(
        f'sum(rate(http_requests_total{{status!~"4.."}}[{window}]))'
    )
    value = good / total if total else 0.0
    return SLIValue('availability', value, 'ratio', window)

def latency_sli(percentile: float = 0.99,
                window: str = '1h') -> SLIValue:
    # TTLT = time-to-last-token; measures full response completion
    value = prom(
        f'histogram_quantile({percentile},'
        f' rate(llm_ttlt_seconds_bucket[{window}]))'
    )
    return SLIValue(f'p{int(percentile*100)}_latency', value or 0, 's', window)

def eval_pass_rate_sli(window: str = '7d') -> SLIValue:
    # Sampled eval score averaged over 7-day window
    value = prom(
        f'avg_over_time(eval_pass_rate[{window}])'
    )
    return SLIValue('eval_pass_rate', value or 0, 'ratio', window)

def safety_flag_rate_sli(window: str = '24h') -> SLIValue:
    flags = prom(f'rate(safety_flag_total[{window}])')
    total = prom(f'rate(llm_request_total[{window}])')
    value = flags / total if total else 0.0
    return SLIValue('safety_flag_rate', value, 'ratio', window)

def cost_per_request_sli(window: str = '1h') -> SLIValue:
    cost = prom(
        f'sum(rate(llm_token_cost_dollars_total[{window}]))'
    )
    reqs = prom(
        f'sum(rate(llm_request_total[{window}]))'
    )
    value = cost / reqs if reqs else 0.0
    return SLIValue('cost_per_request', value, 'USD', window)

# monitoring/slo_check.py
# Evaluate all SLOs and compute remaining error budget.
from dataclasses import dataclass
from typing import List
from sli_definitions import (
    availability_sli, latency_sli,
    eval_pass_rate_sli, safety_flag_rate_sli,
)

@dataclass
class SLO:
    name: str
    target: float
    direction: str  # 'above' or 'below'
    window: str
    error_budget_percent: float = 0.1  # 0.1% = 99.9% availability

@dataclass
class SLOStatus:
    slo: SLO
    current_value: float
    met: bool
    budget_remaining_percent: float

SLOS = [
    SLO('availability', 0.999, 'above', '30d', 0.1),
    SLO('p99_latency',  2.5,   'below', '1h',  0.0),   # no error budget for latency
    SLO('eval_pass_rate', 0.94, 'above', '7d', 6.0),
    SLO('safety_flag_rate', 0.0005, 'below', '24h', 0.0),
]

def check_slo(slo: SLO, current: float) -> SLOStatus:
    if slo.direction == 'above':
        met = current >= slo.target
        if slo.error_budget_percent > 0:
            budget_used = max(0, slo.target - current) / slo.error_budget_percent * 100
            budget_remaining = max(0.0, 100.0 - budget_used)
        else:
            budget_remaining = 100.0 if met else 0.0
    else:  # below
        met = current <= slo.target
        budget_remaining = 100.0 if met else 0.0
    return SLOStatus(slo, current, met, budget_remaining)

def evaluate_all_slos() -> List[SLOStatus]:
    measurements = [
        ('availability',    availability_sli('30d').value),
        ('p99_latency',     latency_sli(0.99, '1h').value),
        ('eval_pass_rate',  eval_pass_rate_sli('7d').value),
        ('safety_flag_rate', safety_flag_rate_sli('24h').value),
    ]
    results = []
    for slo in SLOS:
        value = dict(measurements)[slo.name]
        results.append(check_slo(slo, value))
    return results

if __name__ == '__main__':
    for s in evaluate_all_slos():
        icon = 'OK' if s.met else 'BREACH'
        print(f'{icon} {s.slo.name}: {s.current_value:.4f} '
              f'(budget: {s.budget_remaining_percent:.1f}% remaining)')
